// ========================================
// ФИНАЛЬНАЯ ВЕРСИЯ v3.0 - ПРЯМОЙ HTML
// Простые HTML таблицы БЕЗ стилей
// ========================================

// ========================================
// КОНСТАНТЫ CALLOUTS (только иконки и заголовки)
// ========================================

const CALLOUT_STYLES = {
  note: { title: 'Заметка', emoji: '📝' },
  info: { title: 'Информация', emoji: 'ℹ️' },
  important: { title: 'Важно', emoji: '🔥' },
  tip: { title: 'Совет', emoji: '💡' },
  warning: { title: 'Внимание', emoji: '⚠️' },
  danger: { title: 'Опасно', emoji: '⛔' },
  question: { title: 'Вопрос', emoji: '❓' },
  success: { title: 'Успех', emoji: '✅' },
  quote: { title: 'Цитата', emoji: '💬' },
  failure: { title: 'Ошибка', emoji: '❌' },
  abstract: { title: 'Резюме', emoji: '📄' },
  summary: { title: 'Итоги', emoji: '📋' }
};

// Алиасы
CALLOUT_STYLES['tldr'] = CALLOUT_STYLES['summary'];
CALLOUT_STYLES['check'] = CALLOUT_STYLES['success'];
CALLOUT_STYLES['done'] = CALLOUT_STYLES['success'];
CALLOUT_STYLES['fail'] = CALLOUT_STYLES['failure'];
CALLOUT_STYLES['missing'] = CALLOUT_STYLES['failure'];
CALLOUT_STYLES['caution'] = CALLOUT_STYLES['warning'];
CALLOUT_STYLES['attention'] = CALLOUT_STYLES['warning'];
CALLOUT_STYLES['help'] = CALLOUT_STYLES['question'];
CALLOUT_STYLES['faq'] = CALLOUT_STYLES['question'];
CALLOUT_STYLES['cite'] = CALLOUT_STYLES['quote'];
CALLOUT_STYLES['error'] = CALLOUT_STYLES['danger'];

// ========================================
// ФУНКЦИЯ: Простая HTML таблица для каллаута
// ========================================

/**
 * Генерирует простую HTML-таблицу БЕЗ CSS стилей
 * Нода "Markdown to HTML" пропустит её как есть
 * Google Docs отобразит как обычную таблицу
 * @param {string} type - Тип каллаута
 * @param {string} title - Заголовок (опционально)
 * @param {string} content - Содержимое
 * @returns {string} HTML таблица
 */
function generateCalloutHTML(type, title, content) {
  const style = CALLOUT_STYLES[type.toLowerCase()] || CALLOUT_STYLES['note'];
  const displayTitle = title || style.title;

  // ЧИСТЫЙ HTML БЕЗ стилей - только структура
  // Google Docs понимает базовые HTML таблицы
  return `
<table>
<tr>
<td><strong>${style.emoji} ${displayTitle}</strong></td>
</tr>
<tr>
<td>${content}</td>
</tr>
</table>
`;
}

// ========================================
// ФУНКЦИЯ: Конвертация каллаутов Obsidian
// ========================================

/**
 * Конвертирует каллауты Obsidian в HTML таблицы
 * @param {string} markdown - Markdown текст
 * @returns {string} Markdown с HTML таблицами вместо каллаутов
 */
function convertCalloutToHTML(markdown) {
  // Паттерн для каллаутов Obsidian
  const calloutRegex = /^>\s*\[!(\w+)\]\s*(.*?)\n((?:^>.*$\n?)*)/gm;

  return markdown.replace(calloutRegex, (match, type, title, content) => {
    // Убираем символ > в начале строк контента
    const cleanContent = content.replace(/^>\s?/gm, '').trim();
    return generateCalloutHTML(type, title, cleanContent);
  });
}

// ========================================
// ФУНКЦИЯ: Конвертация тегов (простая версия)
// ========================================

/**
 * Конвертирует теги в жирный текст с решёткой
 * @param {string} text - Текст с тегами
 * @returns {string} Текст с жирными тегами
 */
function convertTagsToHTML(text) {
  // Паттерн для тегов (избегаем заголовки #)
  const tagRegex = /(?<![#\w])#([а-яА-Яa-zA-Z0-9_-]+)/g;

  return text.replace(tagRegex, (match, tag) => {
    return `**#${tag}**`;
  });
}

