for (const item of $input.all()) {
  let markdown = '';

  // Читаем файл
  try {
    const binaryData = await this.helpers.getBinaryDataBuffer(0, 'data');
    markdown = binaryData.toString('utf-8');
  } catch (error) {
    if (item.binary && item.binary.data && item.binary.data.data) {
      markdown = item.binary.data.data.toString('utf-8');
    } else {
      throw new Error('Не удалось прочитать содержимое файла: ' + error.message);
    }
  }

  // 1. Конвертируем каллауты в HTML таблицы
  markdown = convertCalloutToHTML(markdown);

  // 2. Конвертируем теги в жирный текст
  markdown = convertTagsToHTML(markdown);

  // Возвращаем обработанный markdown
  item.json.processedMarkdown = markdown;
  item.json.originalName = item.json.name.replace(/\.md$/, '');
}

return $input.all();

