        "file": base64HTML,
        "filename": item.json.originalName + ".html"
      },
      "convert-to-docx": {
        "operation": "convert",
        "input": "import-html",
        "output_format": "docx"
      },
      "export-file": {
        "operation": "export/url",
        "input": "convert-to-docx"
      }
    },
    "tag": "n8n-obsidian"
  };

  // 3. Сохраняем готовый payload
  item.json.cloudConvertPayload = cloudConvertPayload;

  // Также сохраняем оригинальные данные
  item.json.outputFileName = item.json.originalName + ".docx";
}

return $input.all();

